sys_variable_value.value:
(function(outputs, steps, stepResult, assertEqual)
{
	var test = new x_snc_devtools.TestAPI(outputs, steps, stepResult, assertEqual);
	
	test.SetResult(true);
	
	function TestCase_ArrayGetElementById(aHaystack,strNeedle,strAttribute,vExpected)
	{
		function TestCase_ArrayGetElementById_CheckResult(vInput,vExpected,vResult)
		{
			if (vExpected == false)
			{
				return (vExpected == vResult);
			}
			if (IsObject(vResult) == false)
			{
				return false;
			}
			return true;
		}
		
		test.TestCase(
			'Function ArrayGetElementById()',
			ArrayGetElementById,
			{
				'aHaystack': aHaystack,
				'strNeedle': strNeedle,
				'strAttribute': strAttribute
			},
			vExpected,
			TestCase_ArrayGetElementById_CheckResult);
	}
		
	TestCase_ArrayGetElementById(null,null,null,false);
	TestCase_ArrayGetElementById(null,'test',null,false);
	TestCase_ArrayGetElementById([],'mars',null,false);

	var aPlanets = [
		{
			id: 'mercury',
			name: 'Mercury',
			position: 1
		},
		{
			id: 'venus',
			name: 'Venus',
			position: 2
		},
		{
			id: 'earth',
			name: 'Earth',
			position: 3
		},
		{
			id: 'mars',
			name: 'Mars',
			position: 4
		}

	];
	TestCase_ArrayGetElementById(aPlanets,'melmac',null,false);
	TestCase_ArrayGetElementById(aPlanets,'venus',null,true);
	TestCase_ArrayGetElementById(aPlanets,'venus','short_description',false);
	TestCase_ArrayGetElementById(aPlanets,'venus','name',false);
	TestCase_ArrayGetElementById(aPlanets,'Venus','name',true);

	
	return test.GetResult();
	
})(outputs, steps, stepResult, assertEqual);
